insert into questions (code, chapter_id, skill_id, source_exam, marks, difficulty, timer_seconds, type, stem_latex, stem_en, options_latex, correct_option, answer_latex, explain_en) values ('kn-g-sandhi-agam02', (select id from chapters where code='kn-g-sandhi'), 105, 'Siri Kannada 8 (textbook)', 1, 'easy', 45, 'mcq', 'ಕೈ + ಅನ್ನು  →  ಕೈಯನ್ನು', 'Which type is this?', '["ಆಗಮಸಂಧಿ", "ಆದೇಶಸಂಧಿ", "ಪ್ರಕೃತಿಭಾವ", "ಲೋಪಸಂಧಿ"]'::jsonb, 0, 'ಆಗಮಸಂಧಿ', 'ಕೈ + ಅನ್ನು → ಕೈಯನ್ನು is ಆಗಮಸಂಧಿ (Agama - a letter is ADDED). A vowel meets a vowel, and a NEW ಯ್ or ವ್ is slipped in between them.');
